const URL = 'https://practice-papers.onrender.com/subject/getSubject'

const getSubject = (setAllSubject, setLoading) => {
    setLoading(true)
    fetch(URL, {
        method: 'get',
        headers: { 'Content-Type': 'application/json' },
    })
        .then((response) => response.json())
        .then((responseJson) => {
            if (responseJson.message === 'success') {
                setAllSubject(responseJson.allSubjects)
                setLoading(false)
            } else {
                setLoading(false)
            }
        })
        .catch((error) => {
            console.log(error.message)
            setLoading(false)
        });
}

export default getSubject;
